#!/usr/bin/env python3
"""DGX DEPLOY v19.34.244 — disable vwap_fade_short (DISABLED_SETUPS blocklist).
vwap_fade_short: 8% win, -4.26R, -$22k/120d. vwap_fade_long (+0.51R) stays on.
Scanner still emits it for monitoring; only TRADING is blocked. Override via
the DISABLED_SETUPS env (comma-sep setup_types).
Idempotent: rewrite files, pytest, git commit && git push, restart."""
import base64, gzip, os, subprocess, sys
FILES = {
    'backend/services/entry_gate.py': '',
    'backend/services/trading_bot_service.py': '',
    'backend/tests/test_v19_34_243_entry_gate.py': '',
}
REPO=os.getcwd()
def main():
    if not os.path.isdir(os.path.join(REPO,"backend","services")):
        print("[FATAL] not repo root"); sys.exit(1)
    for rel,b in FILES.items():
        dst=os.path.join(REPO,rel); os.makedirs(os.path.dirname(dst),exist_ok=True)
        data=gzip.decompress(base64.b64decode(b)); open(dst,"wb").write(data)
        print(f"[WROTE] {rel} ({len(data)} bytes)")
    print("[TEST] pytest v243/244 ...")
    r=subprocess.run([sys.executable,"-m","pytest","backend/tests/test_v19_34_243_entry_gate.py","-q"],cwd=REPO)
    if r.returncode!=0: print("[FATAL] pytest failed — aborting."); sys.exit(2)
    subprocess.run(["git","add"]+list(FILES.keys()),cwd=REPO)
    c=subprocess.run(["git","commit","-m","v19.34.244 — disable vwap_fade_short via DISABLED_SETUPS blocklist"],cwd=REPO)
    if c.returncode!=0: print("[INFO] commit no-op")
    p=subprocess.run(["git","push"],cwd=REPO)
    if p.returncode!=0: print("[WARN] push failed — commit is local")
    print("[RESTART] ./start_backend.sh --force"); subprocess.run(["./start_backend.sh","--force"],cwd=REPO)
    print("[DONE] v19.34.244 deployed. vwap_fade_short is no longer traded.")
if __name__=="__main__": main()
